)(
        input			            			                                        clk	            ,
        input			            			                                        rst	            ,
        input		    [159:0]			                                conv_din	    ,
        input                                                                           din_vld         ,
        input                                                                           din_last        ,
        input           [0:1439]                                   kernel          ,
